{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"span":3,"markdown":"Nouvelles acceptatrices PF : Les volumes chutent progressivement avec des baisses successives jusqu’à –32 % au T3 2025.

